    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Ozempic Body Recomp - 4w 3x/wk',
    'fat_loss',
    3,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Ozempic Body Recomp'
ON CONFLICT DO NOTHING;

